CREATE TABLE members (member_id INT PRIMARY KEY, name VARCHAR(50));
CREATE TABLE books (book_id INT PRIMARY KEY, title VARCHAR(100));
CREATE TABLE loans (loan_id INT PRIMARY KEY, member_id INT, book_id INT, due_date DATE, FOREIGN KEY(member_id) REFERENCES members(member_id), FOREIGN KEY(book_id) REFERENCES books(book_id));
SELECT m.name, b.title FROM loans l INNER JOIN members m ON l.member_id=m.member_id INNER JOIN books b ON l.book_id=b.book_id WHERE l.due_date < CURRENT_DATE;

