def validate_input(value):
    """Validates and sanitizes numeric input, reusable module function."""
    try:
        return int(value)
    except (ValueError, TypeError) as e:
        print('error', e)
        return None

# basic test
assert validate_input('5') == 5

def get_input():
    x = input()
    return int(x)

