def get_user_age():
    try:
        age = int(input('Enter age: '))
        if age < 0:
            raise ValueError('Age cannot be negative')
        return age
    except ValueError as e:
        print(f'Invalid input: {e}')
        return None

def test_get_user_age():
    assert get_user_age() is not None

